def connect(root: Optional[object]) -> Optional[object]:
    if not root:
        return None

    level_start = root
    while level_start:
        curr = level_start
        next_level_start = None
        prev = None

        while curr:
            for child in (curr.left, curr.right):
                if child:
                    if prev:
                        prev.next = child
                    else:
                        next_level_start = child
                    prev = child
            curr = curr.next

        level_start = next_level_start

    return root
